res.sendFile = function sendFile(path, options, callback) {
  var done = callback;
  var req = this.req;
  var res = this;
  var next = req.next;
  var opts = options || {};

  if (!path) {
    throw new TypeError('path argument is required to res.sendFile');
  }

  if (typeof path !== 'string') {
    throw new TypeError('path must be a string to res.sendFile')
  }

  // support function as second arg
  if (typeof options === 'function') {
    done = options;
    opts = {};
  }

  if (!opts.root && !pathIsAbsolute(path)) {
    throw new TypeError('path must be absolute or specify root to res.sendFile');
  }

  // create file stream
  var pathname = encodeURI(path);

  // wire application etag option to send
  opts.etag = this.app.enabled('etag');
  var file = send(req, pathname, opts);

  // transfer
  sendfile(res, file, opts, function (err) {
    if (done) return done(err);
    if (err && err.code === 'EISDIR') return next();

    // next() all but write errors
    if (err && err.code !== 'ECONNABORTED' && err.syscall !== 'write') {
      next(err);
    }
  });
};

function cors(options, req, res, next) {
  var headers = [],
    method = req.method && req.method.toUpperCase && req.method.toUpperCase();

  if (method === 'OPTIONS') {
    // preflight
    headers.push(configureOrigin(options, req));
    headers.push(configureCredentials(options))
    headers.push(configureMethods(options))
    headers.push(configureAllowedHeaders(options, req));
    headers.push(configureMaxAge(options))
    headers.push(configureExposedHeaders(options))
    applyHeaders(headers, res);

    if (options.preflightContinue) {
      next();
    } else {
      // Safari (and potentially other browsers) need content-length 0,
      //   for 204 or they just hang waiting for a body
      res.statusCode = options.optionsSuccessStatus;
      res.setHeader('Content-Length', '0');
      res.end();
    }
  } else {
    // actual response
    headers.push(configureOrigin(options, req));
    headers.push(configureCredentials(options))
    headers.push(configureExposedHeaders(options))
    applyHeaders(headers, res);
    next();
  }
}

function View(name, options) {
  var opts = options || {};

  this.defaultEngine = opts.defaultEngine;
  this.ext = extname(name);
  this.name = name;
  this.root = opts.root;

  if (!this.ext && !this.defaultEngine) {
    throw new Error('No default engine was specified and no extension was provided.');
  }

  var fileName = name;

  if (!this.ext) {
    // get extension from default engine name
    this.ext = this.defaultEngine[0] !== '.'
      ? '.' + this.defaultEngine
      : this.defaultEngine;

    fileName += this.ext;
  }

  if (!opts.engines[this.ext]) {
    // load engine
    var mod = this.ext.slice(1)
    debug('require "%s"', mod)

    // default engine export
    var fn = require(mod).__express

    if (typeof fn !== 'function') {
      throw new Error('Module "' + mod + '" does not provide a view engine.')
    }

    opts.engines[this.ext] = fn
  }

  // store loaded engine
  this.engine = opts.engines[this.ext];

  // lookup path
  this.path = this.lookup(fileName);
}

const helmet: Helmet = Object.assign(
  function helmet(options: Readonly<HelmetOptions> = {}) {
    if (options.constructor?.name === "IncomingMessage") {
      throw new Error(
        "It appears you have done something like `app.use(helmet)`, but it should be `app.use(helmet())`.",
      );
    }

    const middlewareFunctions = getMiddlewareFunctionsFromOptions(options);

    return function helmetMiddleware(
      req: IncomingMessage,
      res: ServerResponse,
      next: (err?: unknown) => void,
    ): void {
      let middlewareIndex = 0;

      (function internalNext(err?: unknown) {
        if (err) {
          next(err);
          return;
        }

        const middlewareFunction = middlewareFunctions[middlewareIndex];
        if (middlewareFunction) {
          middlewareIndex++;
          middlewareFunction(req, res, internalNext);
        } else {
          next();
        }
      })();
    };
  },
  {
    contentSecurityPolicy,
    crossOriginEmbedderPolicy,
    referrerPolicy,
    strictTransportSecurity,
    xFrameOptions,
    xPoweredBy,
  },
);

private validateHttp(): void {
  const { req, scheme, path } = this;
  if (['http'].includes(scheme.type.toLowerCase())) {
    const authHeader =
      req.headers['authorization'] &&
      req.headers['authorization'].toLowerCase();
    // req.cookies will be `undefined` without `cookie-parser` middleware
    const authCookie =
      req.cookies?.[scheme.name] || req.signedCookies?.[scheme.name];

    const type = scheme.scheme && scheme.scheme.toLowerCase();
    if (type === 'bearer') {
      if (authHeader && !authHeader.includes('bearer')) {
        throw Error(`Authorization header with scheme 'Bearer' required`);
      }

      if (!authHeader && !authCookie) {
        if (scheme.in === 'cookie') {
          throw Error(`Cookie authentication required`);
        } else {
          throw Error(`Authorization header required`);
        }
      }
    }

    if (type === 'basic') {
      if (!authHeader) {
        throw Error(`Authorization header required`);
      }
      if (!authHeader.includes('basic')) {
        throw Error(`Authorization header with scheme 'Basic' required`);
      }
    }
  }
}

export function httpMethod(
  method: HTTP_VERBS_ENUM,
  path: string,
  ...middleware: Middleware[]
): HandlerDecorator {
  return (target: DecoratorTarget, key: string): void => {
    const decoratedMiddleware: Middleware[] = getMiddlewareMetadata(
      target,
      key,
    );

    const metadata: ControllerMethodMetadata = {
      key,
      method,
      middleware: middleware.concat(decoratedMiddleware),
      path,
      target,
    };

    let metadataList: ControllerMethodMetadata[] = [];

    if (
      !Reflect.hasOwnMetadata(METADATA_KEY.controllerMethod, target.constructor)
    ) {
      Reflect.defineMetadata(
        METADATA_KEY.controllerMethod,
        metadataList,
        target.constructor,
      );
    } else {
      metadataList = Reflect.getOwnMetadata(
        METADATA_KEY.controllerMethod,
        target.constructor,
      ) as ControllerMethodMetadata[];
    }

    metadataList.push(metadata);
  };
}

public build(): express.Application {
  // The very first middleware to be invoked
  // it creates a new httpContext and attaches it to the
  // current request as metadata using Reflect
  this._app.all('*', (req: Request, res: Response, next: NextFunction) => {
    void (async (): Promise<void> => {
      const httpContext: HttpContext = await this._createHttpContext(
        req,
        res,
        next,
      );
      Reflect.defineMetadata(METADATA_KEY.httpContext, httpContext, req);
      next();
    })();
  });

  // register server-level middleware before anything else
  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition, @typescript-eslint/strict-boolean-expressions
  if (this._configFn) {
    this._configFn.apply(undefined, [this._app]);
  }

  this.registerControllers();

  // register error handlers after controllers
  // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition, @typescript-eslint/strict-boolean-expressions
  if (this._errorConfigFn) {
    this._errorConfigFn.apply(undefined, [this._app]);
  }

  return this._app;
}

async function transform(root: SgRoot<Js>): Promise<string | null> {
  const rootNode = root.root()

  const nodes = rootNode.findAll({
    rule: {
      pattern: '$OBJ.$METHOD($$$ARG)',
    },
    constraints: {
      METHOD: { regex: '^(redirect)$' },
    },
  })

  if (!nodes.length) return null

  const edits: Edit[] = []

  for (const call of nodes) {
    const obj = call.getMatch('OBJ')
    const args = call.getMultipleMatches('ARG')
    if (!obj || args.length < 3) continue

    const objDef = obj.definition({ resolveExternal: false })
    if (!objDef) continue

    // $$$ARG yields argument nodes interleaved with separators, so arg nodes are at 0,2,4...
    const first = args[0]
    const second = args[2]
    if (!first || !second) continue

    // Only transform legacy form redirect(url, status) where second is number
    if (second.is('number') && !first.is('number')) {
      edits.push(call.replace(`${obj.text()}.redirect(${second.text()}, ${first.text()})`))
    }
  }

  if (!edits.length) return null

  return rootNode.commitEdits(edits)
}

export function params(type: PARAMETER_TYPE, parameterName?: string | symbol) {
  return (
    target: object,
    methodName: string | symbol | undefined,
    index: number,
  ): void => {
    let metadataList: ControllerParameterMetadata = {};
    let parameterMetadataList: ParameterMetadata[] = [];
    const parameterMetadata: ParameterMetadata = {
      index,
      injectRoot: parameterName === undefined,
      parameterName,
      type,
    };
    if (
      !Reflect.hasOwnMetadata(
        METADATA_KEY.controllerParameter,
        target.constructor,
      )
    ) {
      parameterMetadataList.unshift(parameterMetadata);
    } else {
      metadataList = Reflect.getOwnMetadata(
        METADATA_KEY.controllerParameter,
        target.constructor,
      ) as ControllerParameterMetadata;
      if (metadataList[methodName as string]) {
        parameterMetadataList = metadataList[methodName as string] || [];
      }
      parameterMetadataList.unshift(parameterMetadata);
    }
    metadataList[methodName as string] = parameterMetadataList;
    Reflect.defineMetadata(
      METADATA_KEY.controllerParameter,
      metadataList,
      target.constructor,
    );
  };
}

export function registerExpressMiddlewareInterceptor<CFG>(
  ctx: Context,
  middlewareFactory: ExpressMiddlewareFactory<CFG>,
  middlewareConfig?: CFG,
  options: MiddlewareInterceptorBindingOptions = {},
) {
  options = {
    injectConfiguration: true,
    global: true,
    group: DEFAULT_MIDDLEWARE_GROUP,
    ...options,
  };
  if (!options.injectConfiguration) {
    let key = options.key;
    if (!key) {
      const name = buildName(middlewareFactory);
      const namespace = options.global
        ? GLOBAL_MIDDLEWARE_INTERCEPTOR_NAMESPACE
        : MIDDLEWARE_INTERCEPTOR_NAMESPACE;
      key = name ? `${namespace}.${name}` : BindingKey.generate(namespace);
    }
    const binding = ctx
      .bind(key!)
      .to(createInterceptor(middlewareFactory, middlewareConfig));
    if (options.global) {
      binding.tag({[ContextTags.GLOBAL_INTERCEPTOR_SOURCE]: 'route'});
      binding.apply(asGlobalInterceptor(options.group));
    }
    return binding;
  }
  const providerClass = defineInterceptorProvider(
    middlewareFactory,
    middlewareConfig,
    options,
  );
  const binding = createMiddlewareInterceptorBinding(providerClass, options);
  ctx.add(binding);
  return binding;
}

export function deprecated(isDeprecated = true) {
  return function deprecatedDecoratorForClassOrMethod(
    // Class or a prototype
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    target: any,
    method?: string,
    // Use `any` to for `TypedPropertyDescriptor`
    // See https://github.com/loopbackio/loopback-next/pull/2704
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    methodDescriptor?: TypedPropertyDescriptor<any>,
  ) {
    debug(target, method, methodDescriptor);

    if (method && methodDescriptor) {
      // Method
      return MethodDecoratorFactory.createDecorator<boolean>(
        OAI3Keys.DEPRECATED_METHOD_KEY,
        isDeprecated,
        {decoratorName: '@oas.deprecated'},
      )(target, method, methodDescriptor);
    } else if (typeof target === 'function' && !method && !methodDescriptor) {
      // Class
      return ClassDecoratorFactory.createDecorator<boolean>(
        OAI3Keys.DEPRECATED_CLASS_KEY,
        isDeprecated,
        {decoratorName: '@oas.deprecated'},
      )(target);
    } else {
      throw new Error(
        '@oas.deprecated cannot be used on a property: ' +
          DecoratorFactory.getTargetName(target, method, methodDescriptor),
      );
    }
  };
}

function normalizeOptions (options, defaultType) {
  if (!defaultType) {
    // Parsers must define a default content type
    throw new TypeError('defaultType must be provided')
  }

  const inflate = options?.inflate !== false
  const limit = typeof options?.limit === 'undefined' || options?.limit === null
    ? 102400 // 100kb default
    : bytes.parse(options.limit)
  const type = options?.type || defaultType
  const verify = options?.verify || false
  const defaultCharset = options?.defaultCharset || 'utf-8'

  if (limit === null) {
    throw new TypeError(`option limit "${String(options.limit)}" is invalid`)
  }

  if (verify !== false && typeof verify !== 'function') {
    throw new TypeError('option verify must be function')
  }

  // create the appropriate type checking function
  const shouldParse = typeof type !== 'function'
    ? typeChecker(type)
    : type

  return {
    inflate,
    limit,
    verify,
    defaultCharset,
    shouldParse
  }
}

async function refresh({ tokenEndpointParams } = {}) {
  let { config, req } = weakRef(this);
  const { configuration } = await getClient(config);
  const oldTokenSet = tokenSet.call(this);

  let parameters;
  if (config.tokenEndpointParams || tokenEndpointParams) {
    parameters = { ...config.tokenEndpointParams, ...tokenEndpointParams };
  }

  const newTokenSet = await oidcClient.refreshTokenGrant(
    configuration,
    oldTokenSet.refresh_token,
    parameters,
  );

  // Update the session
  const session = req[config.session.name];
  Object.assign(session, {
    access_token: newTokenSet.access_token,
    // If no new ID token assume the current ID token is valid.
    id_token: newTokenSet.id_token || oldTokenSet.id_token,
    // If no new refresh token assume the current refresh token is valid.
    refresh_token: newTokenSet.refresh_token || oldTokenSet.refresh_token,
    token_type: normalizeTokenType(newTokenSet.token_type),
    expires_at: newTokenSet.expires_in
      ? Math.floor(Date.now() / 1000) + newTokenSet.expires_in
      : undefined,
  });

  // Delete the old token set
  const cachedTokenSet = weakRef(session);
  delete cachedTokenSet.value;

  return this.accessToken;
}

function normalizeDirectives(
  options: Readonly<ContentSecurityPolicyOptions>,
): NormalizedDirectives {
  const defaultDirectives = getDefaultDirectives();
  const { useDefaults = true, directives: rawDirectives = defaultDirectives } =
    options;
  const result: NormalizedDirectives = new Map();
  const directiveNamesSeen = new Set<string>();
  const disabled = new Set<string>();

  for (const rawName in rawDirectives) {
    if (!Object.hasOwn(rawDirectives, rawName)) continue;
    const name = dashify(rawName);
    if (directiveNamesSeen.has(name)) {
      throw new Error(`CSP duplicate: ${JSON.stringify(name)}`);
    }
    directiveNamesSeen.add(name);

    const rawVal = rawDirectives[rawName];
    if (rawVal === null) {
      disabled.add(name);
      continue;
    }
    const val = typeof rawVal === "string" ? [rawVal] : rawVal;
    result.set(name, val);
  }

  if (useDefaults) {
    Object.entries(defaultDirectives).forEach(([n, v]) => {
      if (!result.has(n) && !disabled.has(n)) result.set(n, v);
    });
  }

  return result;
}

export function TypeOrmMixin<T extends MixinTarget<Application>>(
  superClass: T,
) {
  return class extends superClass {
    connectionManager: ConnectionManager;

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    constructor(...args: any[]) {
      super(...args);
      this.component(TypeOrmComponent);
      this.connectionManager = new ConnectionManager();
      const binding: Binding<ConnectionManager> = this.bind(
        TypeOrmBindings.MANAGER,
      ).to(this.connectionManager);
      debug('Binding created for connection manager', binding);
    }

    connection(connectionConfig: ConnectionOptions) {
      const connection: Connection =
        this.connectionManager.create(connectionConfig);
      const name = connection.name;
      const binding: Binding<Connection> = this.bind(
        `${TypeOrmBindings.PREFIX}.${name}`,
      )
        .toDynamicValue(() => this.connectionManager.get(name))
        .tag(TypeOrmBindings.TAG);
      this.add(binding);
      return binding;
    }

    async migrateSchema(): Promise<void> {
      // TODO: implement using TypeORM
      throw new Error('TypeORM migration not implemented.');
    }
  };
}

function buildEndSessionUrl(
  config,
  { configuration, serverMetadata, auth0Logout },
  params,
) {
  // Filter out null and undefined values from params
  const filteredParams = Object.fromEntries(
    Object.entries(params).filter(
      ([, value]) => value !== null && value !== undefined,
    ),
  );

  if (auth0Logout) {
    const { id_token_hint, post_logout_redirect_uri, ...extraParams } =
      filteredParams;
    const logoutUrl = new URL('/v2/logout', serverMetadata.issuer);

    // Add query parameters in the expected order
    if (post_logout_redirect_uri) {
      logoutUrl.searchParams.set('returnTo', post_logout_redirect_uri);
    }
    logoutUrl.searchParams.set('client_id', config.clientID);

    // Add any extra params (already filtered for null/undefined by filteredParams)
    Object.entries(extraParams).forEach(([key, value]) => {
      logoutUrl.searchParams.set(key, value);
    });

    return logoutUrl.toString();
  }

  // Use standard RP-Initiated Logout
  return client.buildEndSessionUrl(configuration, filteredParams).toString();
}

private async isTargetPluginSupported(
  targetPluginId: string,
): Promise<boolean> {
  if (this.supportedTargetPlugins.has(targetPluginId)) {
    return true;
  }
  const inFlight = this.targetPluginInflightChecks.get(targetPluginId);
  if (inFlight) {
    return inFlight;
  }

  const doCheck = async () => {
    try {
      const res = await fetch(
        `${await this.discovery.getBaseUrl(
          targetPluginId,
        )}/.backstage/auth/v1/jwks.json`,
      );
      if (res.status === 404) {
        return false;
      }

      if (!res.ok) {
        throw new Error(`Failed to fetch jwks.json, ${res.status}`);
      }

      const data = await res.json();
      if (!data.keys) {
        throw new Error(`Invalid jwks.json response, missing keys`);
      }

      this.supportedTargetPlugins.add(targetPluginId);
      return true;
    } catch (error) {
      this.logger.error(
        'Unexpected failure for target JWKS check',
        toError(error),
      );
      return false;
    } finally {
      this.targetPluginInflightChecks.delete(targetPluginId);
    }
  };

  const check = doCheck();
  this.targetPluginInflightChecks.set(targetPluginId, check);
  return check;
}

async function sendVerificationEmail(ctx) {
  ctx.state.user = await ctx.state.user.sendVerificationEmail(ctx);

  // attempt to send them an email
  try {
    await email({
      template: 'verify',
      message: {
        to: ctx.state.user[config.userFields.fullEmail]
      },
      locals: {
        user: ctx.state.user.toObject(),
        expiresAt: ctx.state.user[config.userFields.verificationPinExpiresAt],
        pin: ctx.state.user[config.userFields.verificationPin],
        link: `${config.urls.web}${config.verifyRoute}?pin=${
          ctx.state.user[config.userFields.verificationPin]
        }`
      }
    });
  } catch (err) {
    logger.error(err);
    // reset if there was an error
    try {
      ctx.state.user = await ctx.state.user.sendVerificationEmail(ctx, true);
    } catch (err) {
      logger.error(err);
    }

    throw Boom.badRequest(ctx.translateError('EMAIL_FAILED_TO_SEND'));
  }

  return ctx.state.user;
}

constructor(server: OpenAPIV3.ServerObject) {
  // break the url into parts
  // baseUrl param added to make the parsing of relative paths go well
  let urlPath = this.findUrlPath(server.url);
  if (/:/.test(urlPath)) {
    // escape colons as (any at this point) do not signify express route params.
    // this is an openapi base path, thus route params are wrapped in braces {},
    // not prefixed by colon : (like express route params)
    urlPath = urlPath.replace(':','\\:')
  }
  if (/{\w+}/.test(urlPath)) {
    // has variable that we need to check out
    urlPath = urlPath.replace(/{(\w+)}/g, (substring, p1) => `:"${p1}"`);
  }
  this.expressPath = urlPath;
  for (const variable in server.variables) {
    if (server.variables.hasOwnProperty(variable)) {
      const v = server.variables[variable];
      const enums = v.enum ?? [];
      if (enums.length === 0 && v.default) enums.push(v.default);

      this.variables[variable] = {
        enum: enums,
        default: v.default,
      };
    }
  }
}

private explodedJsonObjectAndMutateRequest(
  req: Request,
  $in: string,
  name: string,
  properties: string[],
  schema: SchemaObject,
): void {
  // forcing convert to object if scheme describes param as object + explode
  // for easy validation, keep the schema but update whereabouts of its sub components
  const field = REQUEST_FIELDS[$in];
  if (req[field]) {
    // check if there is at least one of the nested properties before creating the root property
    const atLeastOne = properties.some((p) => {
      return Object.prototype.hasOwnProperty.call(req[field], p);
    });
    if (atLeastOne) {
      req[field][name] = {};
      properties.forEach((property) => {
        if (req[field][property]) {
          const schema = this.parsedSchema[field];
          const type = schema.properties[name].properties?.[property]?.type;
          const value = req[field][property];
          const coercedValue =
            type === 'array' && !Array.isArray(value) ? [value] : value;
          req[field][name][property] = coercedValue;
          delete req[field][property];
        }
      });
    }
  }
}

public process(): { [key: string]: any } {
  const literalBracketParams = this.getLiteralBracketParams();

  const query = this.query;
  Object.keys(query).forEach((key) => {
    // Only process keys that contain brackets
    if (key.includes('[')) {
      // Only process keys that do not contain literal bracket notation
      if (!literalBracketParams.has(key)) {
        // Use qs.parse to handle it as a nested object
        const normalizedKey = key.split('[')[0];
        const parsed = parse(`${key}=${query[key]}`);

        // Use the parsed value for the normalized key
        if (parsed[normalizedKey] !== undefined) {
          // If we already have a value for this key, merge the objects
          if (
            query[normalizedKey] &&
            typeof query[normalizedKey] === 'object' &&
            typeof parsed[normalizedKey] === 'object' &&
            !Array.isArray(parsed[normalizedKey])
          ) {
            query[normalizedKey] = {
              ...query[normalizedKey],
              ...parsed[normalizedKey],
            };
          } else {
            query[normalizedKey] = parsed[normalizedKey];
          }
        }

        // Remove the original bracketed key from the query
        delete query[key];
      }
    }
  });

  return query;
}

creationStack(store: Store) {
	const { stack } = new Error(
		'express-rate-limit validation check (set options.validate.creationStack=false to disable)',
	)

	if (
		stack?.includes('Layer.handle [as handle_request]') || // express v4
		stack?.includes('Layer.handleRequest') // express v5
	) {
		if (!store.localKeys) {
			// This means the user is using an external store, which may be safe.
			// Print out an error anyways, to alert them of the possibility that
			// the rate limiter may not work as intended.

			// See the discussion here: https://github.com/express-rate-limit/express-rate-limit/pull/461#discussion_r1626940562.
			throw new ValidationError(
				'ERR_ERL_CREATED_IN_REQUEST_HANDLER',
				'express-rate-limit instance should *usually* be created at app initialization, not when responding to a request.',
			)
		}

		// Otherwise, make sure they know not to do this.
		throw new ValidationError(
			'ERR_ERL_CREATED_IN_REQUEST_HANDLER',
			'express-rate-limit instance should be created at app initialization, not when responding to a request.',
		)
	}
}

export function readAccessRestrictionsFromConfig(
  externalAccessEntryConfig: Config,
): AccessRestrictionsMap | undefined {
  const configs =
    externalAccessEntryConfig.getOptionalConfigArray('accessRestrictions') ??
    [];

  const result: AccessRestrictionsMap = new Map();
  for (const config of configs) {
    const validKeys = ['plugin', 'permission', 'permissionAttribute'];
    for (const key of config.keys()) {
      if (!validKeys.includes(key)) {
        const valid = validKeys.map(k => `'${k}'`).join(', ');
        throw new Error(
          `Invalid key '${key}' in 'accessRestrictions' config, expected one of ${valid}`,
        );
      }
    }

    const pluginId = config.getString('plugin');
    const permissionNames = readPermissionNames(config);
    const permissionAttributes = readPermissionAttributes(config);

    if (result.has(pluginId)) {
      throw new Error(
        `Attempted to declare 'accessRestrictions' twice for plugin '${pluginId}', which is not permitted`,
      );
    }

    result.set(pluginId, {
      ...(permissionNames ? { permissionNames } : {}),
      ...(permissionAttributes ? { permissionAttributes } : {}),
    });
  }

  return result.size ? result : undefined;
}

export async function ensureMysqlDatabaseExists(
  dbConfig: Config,
  ...databases: Array<string>
) {
  const admin = createMysqlDatabaseClient(dbConfig, {
    connection: {
      database: null as unknown as string,
    },
    pool: {
      min: 0,
      acquireTimeoutMillis: 10000,
    },
  });

  try {
    const ensureDatabase = async (database: string) => {
      await admin.raw(`CREATE DATABASE IF NOT EXISTS ??`, [database]);
    };
    await Promise.all(
      databases.map(async database => {
        // For initial setup we use a smaller timeout but several retries. Given that this
        // is a separate connection pool we should never really run into issues with connection
        // acquisition timeouts, but we do anyway. This might be a bug in knex or some other dependency.
        let lastErr: Error | undefined = undefined;
        for (let i = 0; i < 3; i++) {
          try {
            return await ddlLimiter(() => ensureDatabase(database));
          } catch (err) {
            lastErr = err;
          }
          await new Promise(resolve => setTimeout(resolve, 100));
        }
        throw lastErr;
      }),
    );
  } finally {
    await admin.destroy();
  }
}

async function mapper(_id) {
  // return early if the job was already cancelled
  if (isCancelled) return;

  try {
    const user = await Users.findById(_id);

    // user could have been deleted in the interim
    if (!user) return;

    // check if they already enabled it
    // in the interim if so return early
    if (user[config.passport.fields.otpEnabled]) return;

    // in case email was sent for whatever reason
    if (user[config.userFields.twoFactorReminderSentAt]) return;

    // send email
    await email({
      template: 'two-factor-reminder',
      message: {
        to: user[config.userFields.fullEmail]
      },
      locals: { user: user.toObject() }
    });

    // store that we sent this email
    await Users.findByIdAndUpdate(user._id, {
      $set: {
        [config.userFields.twoFactorReminderSentAt]: new Date()
      }
    });
  } catch (err) {
    logger.error(err);
  }
}

export function createServiceBinding<S>(
  cls: ServiceOrProviderClass<S>,
  options: ServiceOptions = {},
): Binding<S> {
  let name = options.name;
  if (!name && isProviderClass(cls)) {
    // Trim `Provider` from the default service name
    // This is needed to keep backward compatibility
    const templateFn = bindingTemplateFor(cls);
    const template = Binding.bind<S>('template').apply(templateFn);
    if (
      template.tagMap[ContextTags.PROVIDER] &&
      !template.tagMap[ContextTags.NAME]
    ) {
      // The class is a provider and no `name` tag is found
      name = cls.name.replace(/Provider$/, '');
    }
  }
  if (!name && isDynamicValueProviderClass(cls)) {
    // Trim `Provider` from the default service name
    const templateFn = bindingTemplateFor(cls);
    const template = Binding.bind<S>('template').apply(templateFn);
    if (
      template.tagMap[ContextTags.DYNAMIC_VALUE_PROVIDER] &&
      !template.tagMap[ContextTags.NAME]
    ) {
      // The class is a provider and no `name` tag is found
      name = cls.name.replace(/Provider$/, '');
    }
  }
  const binding = createBindingFromClass(cls, {
    name,
    type: CoreTags.SERVICE,
    ...options,
  }).apply(asService(options.interface ?? cls));
  return binding;
}

export const getValidations = (
	_enabled: boolean | EnabledValidations,
	logger: Logger,
): Validations => {
	validateLogger(logger)

	let enabled: { [key: string]: boolean }
	if (typeof _enabled === 'boolean') {
		enabled = {
			default: _enabled,
		}
	} else {
		enabled = {
			default: true,
			..._enabled,
		}
	}

	const wrappedValidations = { enabled } as Validations
	// Wrap all validations to handle disabling and thrown errors
	for (const [name, validation] of Object.entries(validations)) {
		if (typeof validation === 'function')
			(wrappedValidations as { [index: string]: any })[name] = (
				...args: any[]
			) => {
				if (!(enabled[name] ?? enabled.default)) {
					return
				}

				try {
					;(validation as (...args: any[]) => void).apply(
						wrappedValidations,
						args,
					)
				} catch (error: any) {
					if (error instanceof ChangeWarning) logger.warn(error)
					else logger.error(error)
				}
			}
	}

	return wrappedValidations
}

module.exports = async (token, config) => {
  const {
    session: {
      absoluteDuration,
      rolling: rollingEnabled,
      rollingDuration,
      store,
    },
    backchannelLogout,
  } = config;
  const backchannelLogoutStore =
    (backchannelLogout && backchannelLogout.store) || store;
  const maxAge =
    (rollingEnabled
      ? Math.min(absoluteDuration, rollingDuration)
      : absoluteDuration) * 1000;
  const payload = {
    // The "cookie" prop makes the payload compatible with
    // `express-session` stores.
    cookie: {
      expires: Date.now() + maxAge,
      maxAge,
    },
  };
  const set = safePromisify(backchannelLogoutStore.set, backchannelLogoutStore);
  const { iss, sid, sub } = token;
  if (!sid && !sub) {
    throw new Error(`The Logout Token must have a 'sid' or a 'sub'`);
  }
  await Promise.all([
    sid && set(`${iss}|${sid}`, payload),
    sub && set(`${iss}|${sub}`, payload),
  ]);
};

private schemaVisitor(
  parent: SchemaObjectNode,
  node: SchemaObjectNode,
  opts: TraversalStates,
) {
  const pschemas = [parent?.schema];
  const nschemas = [node.schema];

  if (this.apiDocRes) {
    const p = _get(this.apiDocRes, parent?.path);
    const n = _get(this.apiDocRes, node?.path);
    pschemas.push(p);
    nschemas.push(n);
  }

  // visit the node in both the request and response schema
  for (let i = 0; i < nschemas.length; i++) {
    const kind = i === 0 ? 'req' : 'res';
    const pschema = pschemas[i];
    const nschema = nschemas[i];
    const options = opts[kind];
    options.path = node.path;

    if (nschema) {
      // This null check should no longer be necessary
      this.handleSerDes(pschema, nschema, options);
      this.handleReadonly(pschema, nschema, options);
      this.handleWriteonly(pschema, nschema, options);
      this.processDiscriminator(pschema, nschema, options);
      this.removeSchemaExamples(pschema, nschema, options);
    }
  }
}

